import{c as i,$ as l,Q as t,j as n,m as r,h as a,ax as o,n as C,o as A,S as B}from"./chunks/framework.D5MFXpji.js";const h=JSON.parse('{"title":"View System","description":"","frontmatter":{"title":"View System","order":3},"headers":[],"relativePath":"ko/view-system/index.md","filePath":"ko/view-system/index.md","lastUpdated":1781144716000}'),E={name:"ko/view-system/index.md"};function g(d,e,f,c,m,w){const s=l("Mermaid");return t(),n("div",null,[e[1]||(e[1]=r('<h1 id="view-system" tabindex="-1">View System <a class="header-anchor" href="#view-system" aria-label="Permalink to &quot;View System&quot;">​</a></h1><p>앞서 학습한 <strong>RedGPUContext</strong> 가 엔진이 실행될 &#39;환경&#39;이라면, <strong>View System</strong> 은 그 환경 위에서 실제 콘텐츠가 어떻게 보여질지를 결정하는 &#39;틀&#39;입니다.</p><p>RedGPU 의 <strong>View System</strong> 은 엔진의 핵심 아키텍처로서 다음과 같은 역할을 수행합니다.</p><ul><li><strong>장면 구성</strong>: 3D 공간 내 객체와 조명의 계층적 배치 정의</li><li><strong>파이프라인 제어</strong>: 렌더링 프로세스 및 데이터 흐름 관리</li><li><strong>화면 출력</strong>: 최종 결과물을 브라우저 화면에 표시</li></ul><h2 id="핵심-구성-요소" tabindex="-1">핵심 구성 요소 <a class="header-anchor" href="#핵심-구성-요소" aria-label="Permalink to &quot;핵심 구성 요소&quot;">​</a></h2><p>RedGPU의 렌더링 파이프라인을 구성하는 4가지 핵심 모듈입니다.</p><ul><li><strong>View3D</strong> (<code>RedGPU.Display.View3D</code>) <ul><li><strong>역할</strong>: 화면 출력 영역(Viewport/Scissor) 지정</li><li><strong>기능</strong>: 스카이박스 및 포스트 이펙트 적용, 디버깅 도구 관리</li></ul></li><li><strong>Scene</strong> (<code>RedGPU.Display.Scene</code>) <ul><li><strong>역할</strong>: 렌더링될 객체의 계층 구조 관리</li><li><strong>기능</strong>: 조명 데이터 및 씬 배경색 관리</li></ul></li><li><strong>Camera</strong> (<code>RedGPU.Camera.*</code>) <ul><li><strong>역할</strong>: 3D 공간을 2D 화면으로 변환</li><li><strong>기능</strong>: 투영(Projection) 및 뷰(View) 행렬 계산, 절두체 정보 제공</li></ul></li><li><strong>Controller</strong> (<code>RedGPU.Camera.*Controller</code>) <ul><li><strong>역할</strong>: 사용자 입력 감지 및 카메라 연동</li><li><strong>기능</strong>: 마우스/터치/키보드 입력을 통한 카메라 트랜스폼 실시간 갱신</li></ul></li></ul><hr><h2 id="관계-이해하기" tabindex="-1">관계 이해하기 <a class="header-anchor" href="#관계-이해하기" aria-label="Permalink to &quot;관계 이해하기&quot;">​</a></h2><p>학습을 시작하기 전, 이 요소들이 서로 어떻게 연결되는지 이해하는 것이 중요합니다.</p>',10)),(t(),a(B,null,{default:o(()=>[A(s,{id:"mermaid-109",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20Context%5BRedGPUContext%5D%0A%20%20%20%20%0A%20%20%20%20subgraph%20MainView%20%5BView3D%3A%20%EB%A9%94%EC%9D%B8%20%EB%B7%B0%5D%0A%20%20%20%20%20%20%20%20View1%5BView3D%20%EC%9D%B8%EC%8A%A4%ED%84%B4%EC%8A%A4%5D%0A%20%20%20%20%20%20%20%20Camera1%5BCamera%3A%20%EB%A9%94%EC%9D%B8%20%EC%B9%B4%EB%A9%94%EB%9D%BC%5D%0A%20%20%20%20%20%20%20%20View1%20--%3E%7C%EC%86%8C%EC%9C%A0%20(view.camera)%7C%20Camera1%0A%20%20%20%20end%0A%20%20%20%20%0A%20%20%20%20subgraph%20MiniView%20%5BView3D%3A%20%EB%AF%B8%EB%8B%88%EB%A7%B5%20%EB%B7%B0%5D%0A%20%20%20%20%20%20%20%20View2%5BView3D%20%EC%9D%B8%EC%8A%A4%ED%84%B4%EC%8A%A4%5D%0A%20%20%20%20%20%20%20%20Camera2%5BCamera%3A%20%ED%83%91%EB%8B%A4%EC%9A%B4%20%EC%B9%B4%EB%A9%94%EB%9D%BC%5D%0A%20%20%20%20%20%20%20%20View2%20--%3E%7C%EC%86%8C%EC%9C%A0%20(view.camera)%7C%20Camera2%0A%20%20%20%20end%0A%20%20%20%20%0A%20%20%20%20Scene%5BScene%3A%203D%20%EB%AC%B4%EB%8C%80%5D%0A%20%20%20%20%0A%20%20%20%20Context%20--%3E%7C%EC%86%8C%EC%9C%A0%20%26%20%EB%A0%8C%EB%8D%94%EB%A7%81%7C%20View1%0A%20%20%20%20Context%20--%3E%7C%EC%86%8C%EC%9C%A0%20%26%20%EB%A0%8C%EB%8D%94%EB%A7%81%7C%20View2%0A%20%20%20%20%0A%20%20%20%20View1%20--%3E%7C%EC%86%8C%EC%9C%A0%2F%EC%B0%B8%EC%A1%B0%20(view.scene)%7C%20Scene%0A%20%20%20%20View2%20--%3E%7C%EC%86%8C%EC%9C%A0%2F%EC%B0%B8%EC%A1%B0%20(view.scene)%7C%20Scene%0A%20%20%20%20%0A%20%20%20%20Controller1%5BController%5D%20--%3E%7C%EC%B9%B4%EB%A9%94%EB%9D%BC%20%EC%A0%9C%EC%96%B4%7C%20Camera1%0A%20%20%20%20Controller2%5BController%5D%20--%3E%7C%EC%B9%B4%EB%A9%94%EB%9D%BC%20%EC%A0%9C%EC%96%B4%7C%20Camera2%0A%20%20%20%20%0A%20%20%20%20Scene%20--%3E%20Meshes%5BMesh%203D%20%2F%20Lights%5D%0A%0A%20%20%20%20style%20Context%20fill%3A%234a154b%2Cstroke%3A%23fff%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20View1%20fill%3A%230f4c81%2Cstroke%3A%23fff%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20View2%20fill%3A%230f4c81%2Cstroke%3A%23fff%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20Scene%20fill%3A%231f6f43%2Cstroke%3A%23fff%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20Camera1%20fill%3A%23d9534f%2Cstroke%3A%23fff%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20Camera2%20fill%3A%23d9534f%2Cstroke%3A%23fff%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[C(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=r('<ol><li><strong>RedGPUContext</strong> 는 하나 이상의 <strong>View3D</strong> 를 가집니다. (예: 게임 화면과 미니맵)</li><li>각 <strong>View3D</strong> 는 무엇을 보여줄지(<strong>Scene</strong>)와 어디서 볼지(<strong>Camera</strong>)를 연결합니다.</li><li><strong>Controller</strong> 는 사용자의 입력을 받아 <strong>Camera</strong> 를 움직입니다.</li></ol><p>이러한 구조 덕분에 하나의 <strong>Scene</strong> 을 여러 개의 <strong>View3D</strong> 를 통해 서로 다른 각도에서 동시에 볼 수 있습니다.</p><hr><h2 id="학습-로드맵" tabindex="-1">학습 로드맵 <a class="header-anchor" href="#학습-로드맵" aria-label="Permalink to &quot;학습 로드맵&quot;">​</a></h2><p>각 모듈의 상세한 사용법과 설정 방법은 다음 순서로 학습하는 것을 권장합니다.</p><ol><li><strong><a href="./view3d.html">View3D</a></strong> : 화면 렌더링의 기본 단위와 레이아웃 설정 방법.</li><li><strong><a href="./scene.html">Scene</a></strong> : 무대를 구성하고 조명을 관리하는 컨테이너.</li><li><strong><a href="./camera.html">Camera</a></strong> : 3D 좌표를 화면 좌표로 변환하는 시점의 이해.</li><li><strong><a href="./controller.html">Controller</a></strong> : 마우스와 터치를 통한 인터랙티브한 카메라 조작.</li></ol>',6))])}const p=i(E,[["render",g]]);export{h as __pageData,p as default};
